遍历字符串统计字母数和数字数，比较即可。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, ans = 0;
    cin >> n;
    while (n--) {
        string s; cin >> s;
        int letter = 0, digit = 0;
        for (char c : s) {
            if (c >= 'A' && c <= 'Z') letter++;
            else digit++;
        }
        if (digit <= letter) ans++;
    }
    cout << ans << endl;
    return 0;
}
```

枚举 3 到 min(a,b)，检查能否同时整除 a 和 b。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int a, b, cnt = 0;
    cin >> a >> b;
    int mx = min(a, b);
    for (int d = 3; d <= mx; d++)
        if (a % d == 0 && b % d == 0) cnt++;
    cout << cnt << endl;
    return 0;
}
```

枚举内部格子，用方向数组检查 4 个邻居是否都更小。

```cpp
#include <bits/stdc++.h>
using namespace std;
int n, m, g[55][55];
int dx[4] = {-1, 1, 0, 0};
int dy[4] = { 0, 0,-1, 1};
int main() {
    int cnt = 0;
    cin >> n >> m;
    for (int i = 0; i < n; i++)
        for (int j = 0; j < m; j++) cin >> g[i][j];
    for (int i = 1; i < n-1; i++)
        for (int j = 1; j < m-1; j++) {
            bool ok = true;
            for (int d = 0; d < 4; d++)
                if (g[i][j] <= g[i+dx[d]][j+dy[d]]) { ok = false; break; }
            if (ok) cnt++;
        }
    cout << cnt << endl;
    return 0;
}
```

结构体存姓名和三科分数，计算加权最终分，按分降序→姓名升序排序。

```cpp
#include <bits/stdc++.h>
using namespace std;
struct Stu { string nm; int a, b, c, s; } p[1005];
bool cmp(Stu x, Stu y) {
    if (x.s != y.s) return x.s > y.s;
    return x.nm < y.nm;
}
int main() {
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> p[i].nm >> p[i].a >> p[i].b >> p[i].c;
        p[i].s = p[i].a * 3 + p[i].b * 4 + p[i].c * 3;
    }
    sort(p, p + n, cmp);
    for (int i = 0; i < n; i++) cout << p[i].nm << endl;
    return 0;
}
```
